export default function CitationScanline(){const [active,setActive]=useState(0);const reduced=useReducedMotion();return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><p className="text-xs font-extrabold uppercase tracking-[.14em] text-[#4a4a4f]">reading note</p><div aria-label="Citation clauses" className="relative mt-5 flex flex-wrap gap-x-1 border-b border-[#ececee] pb-2">{clauses.map((clause,index)=><button key={clause[0]} type="button" aria-pressed={active===index} onClick={()=>setActive(index)} className="min-h-11 rounded-lg px-1 text-left text-lg font-black text-[#111] outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{clause[0]}</button>)}<motion.i aria-hidden className="absolute -bottom-px h-1 w-20 rounded-full bg-[#b7df38]" animate={{x:active*90}} transition={reduced?{duration:0}:{type:"spring",stiffness:380,damping:28}}/></div><motion.p key={active} initial={{opacity:0}} animate={{opacity:1}} transition={{duration:reduced?.12:.15}} aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">{clauses[active][1]}</motion.p></section>}
